from flask import Flask, request, jsonify
from web3 import Web3
import re
import os
import json

app = Flask(__name__)

# Load environment variables for sensitive data
SECRET_KEY = os.getenv('SECRET_KEY')

# Regular expression to validate Ethereum addresses
ETH_ADDRESS_REGEX = re.compile(r'^0x[a-fA-F0-9]{40}$')

def is_valid_address(address):
    return ETH_ADDRESS_REGEX.match(address) is not None

@app.route('/verify_signature', methods=['POST'])
def verify_signature():
    data = request.json

    # Validate input
    if not data or 'message' not in data or 'signature' not in data or 'address' not in data:
        return jsonify({'error': 'Invalid input'}), 400

    message = data['message']
    signature = data['signature']
    address = data['address']

    if not is_valid_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Recover the address from the signature
    try:
        web3 = Web3()
        recovered_address = web3.eth.account.recover_message(message, signature=signature)

        if recovered_address.lower() == address.lower():
            return jsonify({'status': 'success', 'message': 'Authentication successful'}), 200
        else:
            return jsonify({'status': 'failure', 'message': 'Authentication failed'}), 401
    except Exception as e:
        return jsonify({'error': 'Signature verification failed', 'details': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)